  1→import { getFloorElevation } from '@/domain/floorModels';
  2→import { getSlabBottomLevel } from '@/elevations/slab';
  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { computeLandingElevation } from '@/geometry/landingGeometry';
  5→import { isValidSlabBoundary } from '@/geometry/slabGeometry';
  6→import { getStairRenderData } from '@/geometry/stairGeometry';
  7→import { wallDirection, wallLength, wallOutline } from '@/geometry/wallGeometry';
  8→import { buildWallPreviewContexts, buildWallSolidSegments } from './wallPreviewContext';
  9→
 10→const FIXTURE_3D_HEIGHTS = {
 11→  kitchenTop: 900,
 12→  toilet: 400,
 13→  lavatory: 850,
 14→  table: 750,
 15→  tv: 50,
 16→  sofa: 800,
 17→};
 18→
 19→const DOOR_INSERT_THICKNESS_MIN = 35;
 20→const DOOR_INSERT_THICKNESS_MAX = 70;
 21→const WINDOW_INSERT_THICKNESS_MIN = 45;
 22→const WINDOW_INSERT_THICKNESS_MAX = 90;
 23→
 24→function createBoundsFromPoints(points, baseElevation, topElevation) {
 25→  if (!points?.length) {
 26→    return {
 27→      minX: 0,
 28→      maxX: 0,
 29→      minY: 0,
 30→      maxY: 0,
 31→      minElevation: baseElevation,
 32→      maxElevation: topElevation,
 33→    };
 34→  }
 35→
 36→  return {
 37→    minX: Math.min(...points.map((point) => point.x)),
 38→    maxX: Math.max(...points.map((point) => point.x)),
 39→    minY: Math.min(...points.map((point) => point.y)),
 40→    maxY: Math.max(...points.map((point) => point.y)),
 41→    minElevation: baseElevation,
 42→    maxElevation: topElevation,
 43→  };
 44→}
 45→
 46→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 47→  const topElevation = baseElevation + height;
 48→  return {
 49→    id,
 50→    kind,
 51→    geometry: 'prism',
 52→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 53→    baseElevation,
 54→    height,
 55→    materialKey: metadata.materialKey || kind,
 56→    metadata,
 57→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 58→  };
 59→}
 60→
 61→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 62→  const outline = wallOutline({
 63→    start: { x: startPoint.x, y: startPoint.y },
 64→    end: { x: endPoint.x, y: endPoint.y },
 65→    thickness: width,
 66→  });
 67→  const direction = wallDirection({
 68→    start: { x: startPoint.x, y: startPoint.y },
 69→    end: { x: endPoint.x, y: endPoint.y },
 70→  });
 71→  const topElevation = baseElevation + height;
 72→
 73→  return {
 74→    id,
 75→    kind,
 76→    geometry: 'box',
 77→    center: {
 78→      x: (startPoint.x + endPoint.x) / 2,
 79→      y: (startPoint.y + endPoint.y) / 2,
 80→    },
 81→    size: {
 82→      x: wallLength({ start: startPoint, end: endPoint }),
 83→      y: height,
 84→      z: width,
 85→    },
 86→    rotation: Math.atan2(direction.y, direction.x),
 87→    baseElevation,
 88→    materialKey: metadata.materialKey || kind,
 89→    metadata,
 90→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 91→  };
 92→}
 93→
 94→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 95→  const halfX = size.x / 2;
 96→  const halfZ = size.z / 2;
 97→  const cos = Math.cos(rotation);
 98→  const sin = Math.sin(rotation);
 99→  const corners = [
100→    { x: -halfX, y: -halfZ },
101→    { x: halfX, y: -halfZ },
102→    { x: halfX, y: halfZ },
103→    { x: -halfX, y: halfZ },
104→  ].map((point) => ({
105→    x: center.x + (point.x * cos - point.y * sin),
106→    y: center.y + (point.x * sin + point.y * cos),
107→  }));
108→
109→  return {
110→    id,
111→    kind,
112→    geometry: 'box',
113→    center: { x: center.x, y: center.y },
114→    size,
115→    rotation,
116→    baseElevation,
117→    materialKey: metadata.materialKey || kind,
118→    metadata,
119→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
120→  };
121→}
122→
123→function resolveLandingElevation(landing, stairs, floorLevel) {
124→  if (landing.elevation) return landing.elevation;
125→  return computeLandingElevation(landing, stairs, floorLevel) - floorLevel;
126→}
127→
128→function createStairDescriptor(stair, floorLevel, floorId, landings, landingElevationMap) {
129→  const renderData = getStairRenderData(stair);
130→  if (!renderData?.outline?.length) return null;
131→
132→  let baseElevation = floorLevel;
133→  if (stair.startLandingAttachment) {
134→    const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
135→    if (elev != null) {
136→      baseElevation = floorLevel + elev;
137→    }
138→  }
139→
140→  return {
141→    id: stair.id,
142→    kind: 'stair',
143→    geometry: 'stair',
144→    startPoint: { ...stair.startPoint },
145→    width: stair.width,
146→    numberOfRisers: stair.numberOfRisers,
147→    riserHeight: stair.riserHeight,
148→    treadDepth: stair.treadDepth,
149→    angle: renderData.angle,
150→    baseElevation,
151→    materialKey: 'stair',
152→    metadata: {
153→      sourceId: stair.id,
154→      floorId,
155→    },
156→    bounds: createBoundsFromPoints(
157→      renderData.outline,
158→      baseElevation,
159→      baseElevation + renderData.totalRise
160→    ),
161→  };
162→}
163→
164→function buildWallObjects(wallContexts) {
165→  return wallContexts.flatMap((context) => (
166→    buildWallSolidSegments(context).map((segment) => createLinearBoxDescriptor(
167→      segment.id,
168→      'wall',
169→      segment.startPoint,
170→      segment.endPoint,
171→      segment.thickness,
172→      segment.baseElevation,
173→      segment.topElevation - segment.baseElevation,
174→      {
175→        sourceId: segment.wallId,
176→        floorId: segment.floorId,
177→        wallId: segment.wallId,
178→      }
179→    ))
180→  ));
181→}
182→
183→function buildSlabObjects(floor) {
184→  return (floor.slabs || [])
185→    .filter(slab => isValidSlabBoundary(slab.boundaryPoints))
186→    .map(slab => createPrismDescriptor(
187→      slab.id,
188→      'slab',
189→      slab.boundaryPoints,
190→      getSlabBottomLevel(slab),
191→      slab.thickness ?? 0,
192→      {
193→        sourceId: slab.id,
194→        floorId: floor.id,
195→      }
196→    ));
197→}
198→
199→function buildColumnObjects(floor, floorLevel) {
200→  return (floor.columns || []).map((column) => createBoxDescriptor(
201→    column.id,
202→    'column',
203→    { x: column.x, y: column.y },
204→    {
205→      x: column.width,
206→      y: column.height,
207→      z: column.depth,
208→    },
209→    floorLevel,
210→    (column.rotation || 0) * Math.PI / 180,
211→    {
212→      sourceId: column.id,
213→      floorId: floor.id,
214→    }
215→  ));
216→}
217→
218→function buildBeamObjects(floor) {
219→  return (floor.beams || [])
220→    .map((beam) => {
221→      const renderData = getBeamRenderData(beam, floor.columns || []);
222→      if (!renderData) return null;
223→
224→      return createLinearBoxDescriptor(
225→        beam.id,
226→        'beam',
227→        renderData.start,
228→        renderData.end,
229→        beam.width,
230→        beam.floorLevel - beam.depth,
231→        beam.depth,
232→        {
233→          sourceId: beam.id,
234→          floorId: floor.id,
235→        }
236→      );
237→    })
238→    .filter(Boolean);
239→}
240→
241→function getInsertThickness(kind, wallThickness) {
242→  if (kind === 'door') {
243→    return Math.max(
244→      DOOR_INSERT_THICKNESS_MIN,
245→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
246→    );
247→  }
248→
249→  return Math.max(
250→    WINDOW_INSERT_THICKNESS_MIN,
251→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
252→  );
253→}
254→
255→function createOpeningInsertDescriptor(opening) {
256→  return createBoxDescriptor(
257→    opening.id,
258→    opening.kind,
259→    opening.centerPoint,
260→    {
261→      x: opening.visibleWidth,
262→      y: opening.visibleHeight,
263→      z: getInsertThickness(opening.kind, opening.wallThickness),
264→    },
265→    opening.visibleBaseElevation,
266→    opening.angle,
267→    {
268→      sourceId: opening.sourceId,
269→      floorId: opening.metadata.floorId,
270→      wallId: opening.wallId,
271→      openingKind: opening.kind,
272→    }
273→  );
274→}
275→
276→function buildDoorObjects(wallContexts) {
277→  return wallContexts
278→    .flatMap((context) => context.openings)
279→    .filter((opening) => opening.kind === 'door')
280→    .map((opening) => createOpeningInsertDescriptor(opening));
281→}
282→
283→function buildWindowObjects(wallContexts) {
284→  return wallContexts
285→    .flatMap((context) => context.openings)
286→    .filter((opening) => opening.kind === 'window')
287→    .map((opening) => {
288→      const desc = createOpeningInsertDescriptor(opening);
289→      desc.geometry = 'window';
290→      desc.windowType = opening.type || 'standard';
291→      desc.openDirection = opening.openDirection || 'left';
292→      return desc;
293→    });
294→}
295→
296→function buildStairObjects(floor, floorLevel, landings, landingElevationMap) {
297→  return (floor.stairs || [])
298→    .map((stair) => createStairDescriptor(stair, floorLevel, floor.id, landings, landingElevationMap))
299→    .filter(Boolean);
300→}
301→
302→function buildLandingObjects(floor, floorLevel, landingElevationMap) {
303→  return (floor.landings || []).map((landing) => createBoxDescriptor(
304→    landing.id,
305→    'landing',
306→    { x: landing.position.x, y: landing.position.y },
307→    {
308→      x: landing.width,
309→      y: landing.thickness ?? 200,
310→      z: landing.depth,
311→    },
312→    floorLevel + (landingElevationMap.get(landing.id) || 0),
313→    (landing.rotation || 0) * Math.PI / 180,
314→    {
315→      sourceId: landing.id,
316→      floorId: floor.id,
317→    }
318→  ));
319→}
320→
321→function buildFixtureObjects(floor, floorLevel) {
322→  return (floor.fixtures || []).map((fixture) => createBoxDescriptor(
323→    fixture.id,
324→    'fixture',
325→    { x: fixture.x, y: fixture.y },
326→    {
327→      x: fixture.width,
328→      y: FIXTURE_3D_HEIGHTS[fixture.fixtureType] || 750,
329→      z: fixture.depth,
330→    },
331→    floorLevel,
332→    (fixture.rotation || 0) * Math.PI / 180,
333→    {
334→      sourceId: fixture.id,
335→      floorId: floor.id,
336→      materialKey: 'fixture_' + fixture.fixtureType,
337→    }
338→  ));
339→}
340→
341→export function buildFloorPreviewObjects(floor) {
342→  const floorLevel = getFloorElevation(floor);
343→  const landings = floor.landings || [];
344→  const stairs = floor.stairs || [];
345→
346→  const landingElevationMap = new Map(
347→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorLevel)])
348→  );
349→
350→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
351→
352→  return [
353→    ...buildSlabObjects(floor),
354→    ...buildWallObjects(wallContexts),
355→    ...buildColumnObjects(floor, floorLevel),
356→    ...buildBeamObjects(floor),
357→    ...buildStairObjects(floor, floorLevel, landings, landingElevationMap),
358→    ...buildLandingObjects(floor, floorLevel, landingElevationMap),
359→    ...buildDoorObjects(wallContexts),
360→    ...buildWindowObjects(wallContexts),
361→    ...buildFixtureObjects(floor, floorLevel),
362→  ];
363→}
