 10→function FixtureDetails({ fixture }) {
 11→  const { fixtureType, x, y, width, depth, rotation } = fixture;
 12→  const hw = width / 2, hd = depth / 2;
 13→  const transform = `translate(${x},${y}) rotate(${rotation || 0})`;
 14→
 15→  switch (fixtureType) {
 16→    case 'kitchenTop': {
 17→      // 2x2 burner grid positions
 18→      const bx1 = -hw + width * 0.15, bx2 = -hw + width * 0.35;
 19→      const by1 = -hd + depth * 0.3, by2 = hd - depth * 0.3;
 20→      const bOuter = depth * 0.13, bInner = depth * 0.06;
 21→      // Sink area
 22→      const sx = hw - width * 0.32, sy = -hd * 0.55;
 23→      const sw = width * 0.25, sh = depth * 0.55;
 24→      return (
 25→        <g transform={transform}>
 26→          {/* Countertop seam line */}
 27→          <line x1={-hw + width * 0.52} y1={-hd + depth * 0.05} x2={-hw + width * 0.52} y2={hd - depth * 0.05}
 28→            {...SECONDARY} {...NSS} fill="none" />
 29→          {/* 4 burners */}
 30→          {[[bx1, by1], [bx2, by1], [bx1, by2], [bx2, by2]].map(([cx, cy], i) => (
 31→            <g key={i}>
 32→              <circle cx={cx} cy={cy} r={bOuter} fill="none" {...PRIMARY} {...NSS} />
 33→              <circle cx={cx} cy={cy} r={bInner} fill="none" {...SECONDARY} {...NSS} />
 34→            </g>
 35→          ))}
 36→          {/* Sink basin */}
 37→          <rect x={sx} y={sy} width={sw} height={sh} rx={width * 0.03}
 38→            fill={BLUE_TINT} {...PRIMARY} {...NSS} />
 39→          {/* Sink highlight edge */}
 40→          <rect x={sx + sw * 0.08} y={sy + sh * 0.08} width={sw * 0.84} height={sh * 0.84} rx={width * 0.02}
 41→            fill="none" {...HIGHLIGHT} {...NSS} />
 42→          {/* Drain circle */}
 43→          <circle cx={sx + sw / 2} cy={sy + sh / 2} r={width * 0.015}
 44→            fill="#9E9283" stroke="none" />
 45→          {/* Faucet dot */}
 46→          <circle cx={sx + sw / 2} cy={sy - depth * 0.05} r={width * 0.012}
 47→            fill="#6B5E4F" stroke="none" />
 48→        </g>
 49→      );
 50→    }
 51→    case 'toilet': {
 52→      const cisternH = depth * 0.3;
 53→      const bowlCy = hd * 0.35;
 54→      const bowlRx = width * 0.35, bowlRy = depth * 0.32;
 55→      return (
 56→        <g transform={transform}>
 57→          {/* Cistern */}
 58→          <rect x={-hw + width * 0.1} y={-hd + depth * 0.02} width={width * 0.8} height={cisternH} rx={width * 0.05}
 59→            fill="none" {...PRIMARY} {...NSS} />
 60→          {/* Cistern highlight */}
 61→          <rect x={-hw + width * 0.15} y={-hd + depth * 0.06} width={width * 0.7} height={cisternH * 0.6} rx={width * 0.03}
 62→            fill="none" {...HIGHLIGHT} {...NSS} />
 63→          {/* Flush button */}
 64→          <rect x={-width * 0.08} y={-hd + depth * 0.06} width={width * 0.16} height={cisternH * 0.4} rx={width * 0.02}
 65→            fill="none" {...SECONDARY} {...NSS} />
 66→          {/* Bowl */}
 67→          <ellipse cx={0} cy={bowlCy} rx={bowlRx} ry={bowlRy}
 68→            fill={BLUE_TINT} {...PRIMARY} {...NSS} />
 69→          {/* Inner seat rim */}
 70→          <ellipse cx={0} cy={bowlCy} rx={bowlRx * 0.72} ry={bowlRy * 0.72}
 71→            fill="none" {...SECONDARY} {...NSS} />
 72→          {/* Seat hinge dots */}
 73→          <circle cx={-width * 0.2} cy={-hd + cisternH + depth * 0.06} r={width * 0.02}
 74→            fill="#9E9283" stroke="none" />
 75→          <circle cx={width * 0.2} cy={-hd + cisternH + depth * 0.06} r={width * 0.02}
 76→            fill="#9E9283" stroke="none" />
 77→        </g>
 78→      );
 79→    }
 80→    case 'lavatory': {
 81→      const r = Math.min(width, depth) * 0.3;
 82→      return (
 83→        <g transform={transform}>
 84→          {/* Outer basin */}
 85→          <ellipse cx={0} cy={0} rx={r} ry={r * 0.85}
 86→            fill={BLUE_TINT} {...PRIMARY} {...NSS} />
 87→          {/* Inner bowl highlight */}
 88→          <ellipse cx={0} cy={0} rx={r * 0.7} ry={r * 0.6}
 89→            fill="none" {...HIGHLIGHT} {...NSS} />
 90→          {/* Drain dot */}
 91→          <circle cx={0} cy={0} r={width * 0.015}
 92→            fill="#9E9283" stroke="none" />
 93→          {/* Faucet dots + spout line */}
 94→          <circle cx={-width * 0.06} cy={-hd + depth * 0.12} r={width * 0.015}
 95→            fill="#6B5E4F" stroke="none" />
 96→          <circle cx={width * 0.06} cy={-hd + depth * 0.12} r={width * 0.015}
 97→            fill="#6B5E4F" stroke="none" />
 98→          <line x1={0} y1={-hd + depth * 0.12} x2={0} y2={-hd + depth * 0.22}
 99→            {...SECONDARY} {...NSS} fill="none" />
100→        </g>
101→      );
102→    }
103→    case 'table': {
104→      const inset = width * 0.06;
105→      const legInset = width * 0.1;
106→      const legDInset = depth * 0.1;
107→      const legR = width * 0.035;
108→      return (
109→        <g transform={transform}>
110→          {/* Inner highlight rect (bevel) */}
111→          <rect x={-hw + inset} y={-hd + inset} width={width - inset * 2} height={depth - inset * 2} rx={2}
112→            fill="none" {...HIGHLIGHT} {...NSS} />
113→          {/* Subtle grain lines */}
114→          <line x1={-hw + width * 0.3} y1={-hd + inset} x2={-hw + width * 0.3} y2={hd - inset}
115→            {...SECONDARY} {...NSS} fill="none" opacity={0.4} />
116→          <line x1={-hw + width * 0.65} y1={-hd + inset} x2={-hw + width * 0.65} y2={hd - inset}
117→            {...SECONDARY} {...NSS} fill="none" opacity={0.4} />
118→          {/* 4 legs with outer ring + filled center */}
119→          {[
120→            [-hw + legInset, -hd + legDInset],
121→            [hw - legInset, -hd + legDInset],
122→            [-hw + legInset, hd - legDInset],
123→            [hw - legInset, hd - legDInset],
124→          ].map(([cx, cy], i) => (
125→            <g key={i}>
126→              <circle cx={cx} cy={cy} r={legR} fill="none" {...PRIMARY} {...NSS} />
127→              <circle cx={cx} cy={cy} r={legR * 0.4} fill="#6B5E4F" stroke="none" />
128→            </g>
129→          ))}
130→        </g>
131→      );
132→    }
133→    case 'tv': {
134→      const bezelInset = width * 0.04;
135→      return (
136→        <g transform={transform}>
137→          {/* Inner bezel rect */}
138→          <rect x={-hw + bezelInset} y={-hd + bezelInset} width={width - bezelInset * 2} height={depth - bezelInset * 2}
139→            rx={1} fill="none" {...SECONDARY} {...NSS} />
140→          {/* Power LED dot (green) */}
141→          <circle cx={hw - width * 0.08} cy={hd - depth * 0.25} r={width * 0.012}
142→            fill="#4CAF50" stroke="none" />
143→          {/* Stand mount line */}
144→          <line x1={0} y1={hd} x2={0} y2={hd + depth * 0.3}
145→            {...PRIMARY} {...NSS} fill="none" />
146→          {/* Base bar */}
147→          <line x1={-width * 0.18} y1={hd + depth * 0.3} x2={width * 0.18} y2={hd + depth * 0.3}
148→            {...PRIMARY} {...NSS} fill="none" />
149→        </g>
150→      );
151→    }
152→    case 'sofa': {
153→      const pad = width * 0.04;
154→      const backH = depth * 0.22;
155→      const armW = width * 0.08;
156→      const seatTop = -hd + backH + pad;
157→      const seatBot = hd - pad;
158→      const seatLeft = -hw + armW + pad;
159→      const seatRight = hw - armW - pad;
160→      const seatW = seatRight - seatLeft;
161→      const cushionW = seatW / 3;
162→      return (
163→        <g transform={transform}>
164→          {/* Backrest */}
165→          <rect x={-hw + pad} y={-hd + pad} width={width - pad * 2} height={backH}
166→            rx={width * 0.02} fill="none" {...PRIMARY} {...NSS} />
167→          {/* Left armrest */}
168→          <rect x={-hw + pad} y={-hd + backH} width={armW} height={depth - backH - pad}
169→            rx={width * 0.015} fill="none" {...PRIMARY} {...NSS} />
170→          {/* Right armrest */}
171→          <rect x={hw - armW - pad} y={-hd + backH} width={armW} height={depth - backH - pad}
172→            rx={width * 0.015} fill="none" {...PRIMARY} {...NSS} />
173→          {/* 3 seat cushion rects */}
174→          {[0, 1, 2].map(i => (
175→            <rect key={i}
176→              x={seatLeft + i * cushionW + pad * 0.3}
177→              y={seatTop + pad * 0.3}
178→              width={cushionW - pad * 0.6}
179→              height={seatBot - seatTop - pad * 0.6}
180→              rx={width * 0.01}
181→              fill="none" {...SECONDARY} {...NSS}
182→            />
183→          ))}
184→          {/* Cushion seam dash lines */}
185→          {[1, 2].map(i => (
186→            <line key={i}
187→              x1={seatLeft + i * cushionW} y1={seatTop + pad}
188→              x2={seatLeft + i * cushionW} y2={seatBot - pad}
189→              {...SECONDARY} {...NSS} fill="none"
190→              strokeDasharray="8 6"
191→            />
192→          ))}
193→        </g>
194→      );
195→    }
196→    default:
197→      return null;
198→  }
